+    right: Option<&SourceBlob>,
+) -> bool {
+    match (left, right) {
+        (Some(left), Some(right)) => {
+            left.sha256 == right.sha256
+                && left.git_oid == right.git_oid
+                && left.size_bytes == right.size_bytes
+        }
+        (None, None) => true,
+        _ => false,
+    }
+}
