+                    id,
+                    after_commit_id: None,
+                    source_commit_id: Some(logical_id.clone()),
+                    author_id: staged_update.author_id.clone(),
+                    path: change.path.clone(),
+                    old_visibility,
+                    new_visibility: change.visibility,
+                    current_content: change.new_content.clone(),
+                })
+            } else {
